      /* <flatten type="Javascript"> */
function setItemReadOnly(f, c, v, b) {
  var o = f.getItem(c);
  var grandNode = o.parentNode.parentNode;
  o.disabled = !v;
  if (o.a) $common.setVisible(o.a, v);
  if(!v) f.setItemControlBehavior(c, '', '');
  if(!b) return;
}

function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var l = (f.getItemValue('den_nam') == 0);
  if (l) {
    f.getItem('tu_ky').value = (new Date()).getMonth() + 1;
    f.getItem('den_ky').value = (new Date()).getMonth() + 1;
    f.getItem('tu_nam').value = (new Date()).getFullYear();
    f.getItem('den_nam').value = (new Date()).getFullYear();
  }
  f.live(f.getItem('tu_ky'));
  if (!l) onChange$Filter$ReportForm(f.getItem('ma_dvcs'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc');
      g._hiddenFields = [{Fields: 'gia_nt, tien_nt', Value: x == '10'}, {Fields: 'gia, tien', Value: x == '20'},
        {Fields: 'ma_bp', Value: f._costDept == 0}, {Fields: 'so_lsx', Value: f._costMO == 0}];

      var p1 = f.getItemValue('tu_ky'), y1 = f.getItemValue('tu_nam'), p2 = f.getItemValue('den_ky'), y2 = f.getItemValue('den_nam');
      var v1 = f.getItemValue('ma_sp'), v2 = f.getItemValue('ma_bp'), v3 = f.getItemValue('so_lsx'), v4 = f.getItemValue('ten_sp%l'), s = '', sp = '', bp = '', lsx = '';

      if (f._language == 'v') {sp = ', sản phẩm: '; bp = ', bộ phận: '; lsx = ', lệnh sản xuất: ';}
        else {sp = ', Product: '; bp = ', Department: '; lsx = ', MO: '; }

      if (v1 != '') s = s + sp + v1;
      if (v4 != '') s = s + ' - ' + v4;
      if (v2 != '') s = s + bp + v2;
      if (v3 != '') s = s + lsx + v3;

      g._alterTitle = [null, [['%p1', p1, true], ['%y1', y1, true], ['%p2', p2, true], ['%y2', y2, true], ['%s', s, true]]];
      if (g._$k != null) g._$k = [];
      remove$GridReport$Filter(g);
      break;
    case 'SetReadOnlyField':
      f._costDept = result[0].Value;
      f._costMO = result[1].Value;
      setItemReadOnly(f, 'ma_bp', f._costDept, true);
      setItemReadOnly(f, 'so_lsx', f._costMO, true);
    default:
      break;
  }
}
function onChange$Filter$ReportForm(o) {
  var f = o.parentForm;
  if (f._objectUnit == '1') f.request('GetResponse', 'SetReadOnlyField', ['ma_dvcs']);
}/* </flatten> */

